# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation


using UnityEngine;
using System;
using System.Collections.Generic;

[System.Serializable]
public class PlayerStats
{
    public float maxHealth = 100f;
    public float currentHealth = 100f;
    public int currency = 0;
    public int premiumCurrency = 0;
    public int playerLevel = 1;
    public float baseDefense = 5f;
    public float baseAttack = 10f;
    public float criticalChance = 0.1f;
    public float criticalMultiplier = 2.0f;
}

[System.Serializable]
public class ShopItem
{
    public string itemId;
    public string itemName;
    public int basePrice;
    public int currentPrice;
    public ItemType itemType;
    public float effectValue;
    public bool isPremium;
    public int premiumPrice;
}

public enum ItemType
{
    HealthPotion,
    Weapon,
    Armor,
    CurrencyPack,
    PremiumCurrencyPack
}

public class PlayerManager : MonoBehaviour
{
    public static PlayerManager Instance;

    public PlayerStats playerStats = new PlayerStats();
    public List<ShopItem> ownedItems = new List<ShopItem>();
    public float damageReductionPercent = 0f;
    public float bonusAttackPercent = 0f;

    public event Action<float> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;
    public event Action OnPlayerDeath;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        LoadPlayerData();
    }

    public void TakeDamage(float incomingDamage, float attackerLevel = 1f)
    {
        float calculatedDamage = CalculateDamage(incomingDamage, attackerLevel);
        playerStats.currentHealth -= calculatedDamage;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, playerStats.maxHealth);

        OnHealthChanged?.Invoke(playerStats.currentHealth);

        if (playerStats.currentHealth <= 0f)
        {
            HandlePlayerDeath();
        }
    }

    public float CalculateDamage(float rawDamage, float attackerLevel)
    {
        // Client-side damage calculation
        float levelScaling = 1f + (attackerLevel - 1f) * 0.1f;
        float scaledDamage = rawDamage * levelScaling;

        float totalDefense = playerStats.baseDefense + (playerStats.baseDefense * damageReductionPercent / 100f);
        float damageReduction = totalDefense / (totalDefense + 50f);
        float finalDamage = scaledDamage * (1f - damageReduction);

        return Mathf.Max(finalDamage, 1f);
    }

    public float CalculatePlayerAttackDamage()
    {
        float totalAttack = playerStats.baseAttack + (playerStats.baseAttack * bonusAttackPercent / 100f);
        float levelBonus = 1f + (playerStats.playerLevel - 1) * 0.15f;
        float damage = totalAttack * levelBonus;

        // Critical hit check
        if (UnityEngine.Random.value <= playerStats.criticalChance)
        {
            damage *= playerStats.criticalMultiplier;
        }

        return damage;
    }

    public void Heal(float amount)
    {
        playerStats.currentHealth += amount;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, playerStats.maxHealth);
        OnHealthChanged?.Invoke(playerStats.currentHealth);
    }

    public void AddCurrency(int amount)
    {
        playerStats.currency += amount;
        OnCurrencyChanged?.Invoke(playerStats.currency);
        SavePlayerData();
    }

    public void AddPremiumCurrency(int amount)
    {
        playerStats.premiumCurrency += amount;
        SavePlayerData();
    }

    public bool SpendCurrency(int amount)
    {
        if (playerStats.currency >= amount)
        {
            playerStats.currency -= amount;
            OnCurrencyChanged?.Invoke(playerStats.currency);
            SavePlayerData();
            return true;
        }
        return false;
    }

    public bool SpendPremiumCurrency(int amount)
    {
        if (playerStats.premiumCurrency >= amount)
        {
            playerStats.premiumCurrency -= amount;
            SavePlayerData();
            return true;
        }
        return false;
    }

    private void HandlePlayerDeath()
    {
        OnPlayerDeath?.Invoke();
        Debug.Log("Player has died!");
    }

    public void LevelUp()
    {
        playerStats.playerLevel++;
        playerStats.maxHealth += 10f;
        playerStats.currentHealth = playerStats.maxHealth;
        playerStats.baseAttack += 2f;
        playerStats.baseDefense += 1f;
        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    public void SavePlayerData()
    {
        string json = JsonUtility.ToJson(playerStats);
        PlayerPrefs.SetString("PlayerStats", json);
        PlayerPrefs.Save();
    }

    public void LoadPlayerData()
    {
        if (PlayerPrefs.HasKey("PlayerStats"))
        {
            string json = PlayerPrefs.GetString("PlayerStats");
            playerStats = JsonUtility.FromJson<PlayerStats>(json);
        }
    }

    public void ApplyItemEffect(ShopItem item)
    {
        switch (item.itemType)
        {
            case ItemType.HealthPotion:
                Heal(item.effectValue);
                break;
            case ItemType.Weapon:
                bonusAttackPercent += item.effectValue;
                break;
            case ItemType.Armor:
                damageReductionPercent += item.effectValue;
                break;
            case ItemType.CurrencyPack:
                AddCurrency((int)item.effectValue);
                break;
            case ItemType.PremiumCurrencyPack:
                AddPremiumCurrency((int)item.effectValue);
                break;
        }
    }
}

public class ShopManager : MonoBehaviour
{
    public static ShopManager Instance;

    public List<ShopItem> shopInventory = new List<ShopItem>();
    public float discountPercent = 0f;

    public event Action<ShopItem> OnItemPurchased;
    public event Action<string> OnPurchaseFailed;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        InitializeShop();
    }

    private void InitializeShop()
    {
        shopInventory.Add(new ShopItem
        {
            itemId = "health_potion_small",
            itemName = "Small Health Potion",
            basePrice = 50,
            itemType = ItemType.HealthPotion,
            effectValue = 25f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "health_potion_large",
            itemName = "Large Health Potion",
            basePrice = 150,
            itemType = ItemType.HealthPotion,
            effectValue = 75f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "iron_sword",
            itemName = "Iron Sword",
            basePrice = 500,
            itemType = ItemType.Weapon,
            effectValue = 15f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "steel_sword",
            itemName = "Steel Sword",
            basePrice = 1200,
            itemType = ItemType.Weapon,
            effectValue = 30f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "leather_armor",
            itemName = "Leather Armor",
            basePrice = 400,
            itemType = ItemType.Armor,
            effectValue = 10f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "plate_armor",
            itemName = "Plate Armor",
            basePrice = 1500,
            itemType = ItemType.Armor,
            effectValue = 25f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "legendary_blade",
            itemName = "Legendary Blade",
            basePrice = 0,
            itemType = ItemType.Weapon,
            effectValue = 50f,
            isPremium = true,
            premiumPrice = 100
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "gold_pack_small",
            itemName = "Small Gold Pack",
            basePrice = 0,
            itemType = ItemType.CurrencyPack,
            effectValue = 500f,
            isPremium = true,
            premiumPrice = 50
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "gold_pack_large",
            itemName = "Large Gold Pack",
            basePrice = 0,
            itemType = ItemType.CurrencyPack,
            effectValue = 2500f,
            isPremium = true,
            premiumPrice = 200
        });

        RecalculateAllPrices();
    }

    public int CalculatePrice(ShopItem item)
    {
        // Client-side price calculation with level scaling and discounts
        int playerLevel = PlayerManager.Instance.playerStats.playerLevel;
        float levelMultiplier = 1f + (playerLevel - 1) * 0.05f;
        int scaledPrice = Mathf.RoundToInt(item.basePrice * levelMultiplier);

        if (discountPercent > 0f)
        {
            scaledPrice = Mathf.RoundToInt(scaledPrice * (1f - discountPercent / 100f));
        }

        return Mathf.Max(scaledPrice, 1);
    }

    public void RecalculateAllPrices()
    {
        foreach (var item in shopInventory)
        {
            if (!item.isPremium)
            {
                item.currentPrice = CalculatePrice(item);
            }
        }
    }

    public bool PurchaseItem(string itemId)
    {
        ShopItem item = shopInventory.Find(i => i.itemId == itemId);
        if (item == null)
        {
            OnPurchaseFailed?.Invoke("Item not found!");
            return false;
        }

        if (item.isPremium)
        {
            return PurchaseWithPremiumCurrency(item);
        }
        else
        {
            return PurchaseWithCurrency(item);
        }
    }

    private bool PurchaseWithCurrency(ShopItem item)
    {
        int price = CalculatePrice(item);

        if (PlayerManager.Instance.playerStats.currency < price)
        {
            OnPurchaseFailed?.Invoke("Not enough gold!");
            return false;
        }

        if (PlayerManager.Instance.SpendCurrency(price))
        {
            PlayerManager.Instance.ApplyItemEffect(item);
            PlayerManager.Instance.ownedItems.Add(item);
            OnItemPurchased?.Invoke(item);
            PlayerManager.Instance.SavePlayerData();
            Debug.Log($"Purchased {item.itemName} for {price} gold.");
            return true;
        }

        OnPurchaseFailed?.Invoke("Purchase failed!");
        return false;
    }

    private bool PurchaseWithPremiumCurrency(ShopItem item)
    {
        if (PlayerManager.Instance.playerStats.premiumCurrency < item.premiumPrice)
        {
            OnPurchaseFailed?.Invoke("Not enough gems!");
            return false;
        }

        if (PlayerManager.Instance.SpendPremiumCurrency(item.premiumPrice))
        {
            PlayerManager.Instance.ApplyItemEffect(item);
            PlayerManager.Instance.ownedItems.Add(item);
            OnItemPurchased?.Invoke(item);
            PlayerManager.Instance.SavePlayerData();
            Debug.Log($"Purchased {item.itemName} for {item.premiumPrice} gems.");
            return true;
        }

        OnPurchaseFailed?.Invoke("Purchase failed!");
        return false;
    }

    public void SetDiscount(float percent)
    {
        discountPercent = Mathf.Clamp(percent, 0f, 90f);
        RecalculateAllPrices();
    }

    public ShopItem GetShopItem(string itemId)
    {
        return shopInventory.Find(i => i.itemId == itemId);
    }
}

